import { FastifyInstance, FastifyPluginAsync } from 'fastify'
import { z } from 'zod'
import { authenticate } from '../middleware/auth.js'
import { Article, Category } from '../models/Article.js'

const articleCreateSchema = z.object({
  slug: z.string().min(1),
  title: z.string().min(1),
  excerpt: z.string(),
  content: z.string(),
  category: z.enum(['AI', 'CTDL', 'WEB_DEV', 'DEVOPS', 'MOBILE']),
  tags: z.array(z.string()),
  coverImage: z.string().optional(),
  readingTime: z.number().optional(),
})

const articleUpdateSchema = articleCreateSchema.partial()

const articleQuerySchema = z.object({
  page: z.coerce.number().min(1).default(1),
  limit: z.coerce.number().min(1).max(100).default(10),
  category: z.string().optional(),
  tag: z.string().optional(),
  search: z.string().optional(),
})

const articleRoutes: FastifyPluginAsync = async (fastify: FastifyInstance) => {
  // List articles (public)
  fastify.get('/', async (request, reply) => {
    const query = articleQuerySchema.parse(request.query)
    const skip = (query.page - 1) * query.limit

    const filter: any = { published: true }

    if (query.category) {
      filter.category = query.category.toUpperCase()
    }

    if (query.tag) {
      filter.tags = query.tag
    }

    if (query.search) {
      filter.$or = [
        { title: { $regex: query.search, $options: 'i' } },
        { excerpt: { $regex: query.search, $options: 'i' } },
      ]
    }

    const [articles, total] = await Promise.all([
      Article.find(filter)
        .skip(skip)
        .limit(query.limit)
        .sort({ publishedAt: -1 })
        .populate('authorId', 'name avatar')
        .lean(),
      Article.countDocuments(filter),
    ])

    const formatted = articles.map((a: any) => ({
      ...a,
      id: a._id.toString(),
      author: a.authorId ? {
        id: a.authorId._id.toString(),
        name: a.authorId.name,
        avatar: a.authorId.avatar,
      } : null,
    }))

    return reply.send({
      articles: formatted,
      pagination: {
        page: query.page,
        limit: query.limit,
        total,
        totalPages: Math.ceil(total / query.limit),
      },
    })
  })

  // Get single article by slug
  fastify.get('/:slug', async (request, reply) => {
    const { slug } = request.params as { slug: string }

    const article: any = await Article.findOne({ slug })
      .populate('authorId', 'name avatar')
      .lean()

    if (!article) {
      return reply.status(404).send({ error: 'Article not found' })
    }

    return reply.send({
      ...article,
      id: article._id.toString(),
      author: article.authorId ? {
        id: article.authorId._id.toString(),
        name: article.authorId.name,
        avatar: article.authorId.avatar,
      } : null,
    })
  })

  // Create article (admin only)
  fastify.post('/', { preHandler: authenticate }, async (request, reply) => {
    if (request.user.role !== 'ADMIN') {
      return reply.status(403).send({ error: 'Admin only' })
    }

    const data = articleCreateSchema.parse(request.body)

    const article = await Article.create({
      ...data,
      authorId: request.user.id,
    })

    await article.populate('authorId', 'name avatar')

    return reply.status(201).send(article)
  })

  // Update article (admin only)
  fastify.put('/:id', { preHandler: authenticate }, async (request, reply) => {
    if (request.user.role !== 'ADMIN') {
      return reply.status(403).send({ error: 'Admin only' })
    }

    const { id } = request.params as { id: string }
    const data = articleUpdateSchema.parse(request.body)

    const article = await Article.findByIdAndUpdate(id, data, { new: true }).populate('authorId', 'name avatar')

    if (!article) {
      return reply.status(404).send({ error: 'Article not found' })
    }

    return reply.send(article)
  })

  // Delete article (admin only)
  fastify.delete('/:id', { preHandler: authenticate }, async (request, reply) => {
    if (request.user.role !== 'ADMIN') {
      return reply.status(403).send({ error: 'Admin only' })
    }

    const { id } = request.params as { id: string }

    const article = await Article.findByIdAndDelete(id)

    if (!article) {
      return reply.status(404).send({ error: 'Article not found' })
    }

    return reply.send({ message: 'Article deleted' })
  })

  // Publish/unpublish article (admin only)
  fastify.patch('/:id/publish', { preHandler: authenticate }, async (request, reply) => {
    if (request.user.role !== 'ADMIN') {
      return reply.status(403).send({ error: 'Admin only' })
    }

    const { id } = request.params as { id: string }
    const { published } = request.body as { published: boolean }

    const article = await Article.findByIdAndUpdate(
      id,
      { published, publishedAt: published ? new Date() : null },
      { new: true }
    )

    if (!article) {
      return reply.status(404).send({ error: 'Article not found' })
    }

    return reply.send(article)
  })
}

export default articleRoutes
